import json
import boto3

def process_message(message):
    # Implement your logic to handle each type of message here
    try:
        body = json.loads(message['Body'])
        action_type = body.get('type')
        
        if action_type == 'process_data':
            data = body.get('data')
            # Handle data processing
            print(f"Processing data: {data}")
        elif action_type == 'send_notification':
            notification = body.get('notification')
            # Send notification
            print(f"Sending notification: {notification}")
        else:
            raise ValueError(f"Unknown message type: {action_type}")
    except json.JSONDecodeError:
        print("Invalid JSON in message")
    except KeyError as e:
        print(f"Missing key in message: {e}")

def main():
    sqs = boto3.client('sqs')
    queue_url = 'YOUR_SQS_QUEUE_URL'  # Replace with your SQS queue URL

    while True:
        response = sqs.receive_message(
            QueueUrl=queue_url,
            AttributeNames=['All'],
            MessageAttributeNames=['All'],
            MaxNumberOfMessages=10,
            WaitTimeSeconds=20
        )

        messages = response.get('Messages', [])
        
        for message in messages:
            process_message(message)
            
            # Delete the message from the queue after processing
            sqs.delete_message(
                QueueUrl=queue_url,
                ReceiptHandle=message['ReceiptHandle']
            )

if __name__ == '__main__':
    main()